import sys
def get_num(num, base):
    if num == 0:
        return [0]
    res = []
    while num > 0:
        res.append(num % base)
        num //= base
    return res[::-1]

base = int(input())
k = sys.stdin.readline().strip()
if len(k) == 1:
    print(k)
else:
    k = [int(x) for x in k]
    l = len(k)
    while l > 1:
        for i in range(l):
            if k[i] == 0:
                k[i] = base - 1
            else:
                k[i] -= 1
                break
        if k[l - 1] == 0:
            k.append(0)
            l += 1
        break
    print(int(''.join(str(x) for x in k[::-1])))
